#include <iostream>
#include <string>

class Calculator {
public:
  int add(int a, int b) {
    return a + b;
  }
  double add(double a, double b) {
    return a + b;
  }
};

int main() {
  Calculator calc;
  std::cout << "Int sum: " << calc.add(5, 3) << std::endl;
  std::cout << "Double sum: " << calc.add(5.5, 3.3) << std::endl;
  return 0;
}
// Output:
// Int sum: 8
// Double sum: 8.8

#include <iostream>
#include <string>

class Animal {
public:
  virtual void makeSound() {
    std::cout << "Animal makes a sound" << std::endl;
  }
  virtual ~Animal() {}
};

class Dog : public Animal {
public:
  void makeSound() override {
    std::cout << "Dog barks" << std::endl;
  }
};

class Cat : public Animal {
public:
  void makeSound() override {
    std::cout << "Cat meows" << std::endl;
  }
};

int main() {
  Animal* animal1 = new Dog();
  Animal* animal2 = new Cat();
  animal1->makeSound();
  animal2->makeSound();
  delete animal1;
  delete animal2;
  return 0;
}
// Output:
// Dog barks
// Cat meows

